const App = () => {
    // New State for Landing Page
    const [showLanding, setShowLanding] = useState(true);
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
    const [showAuthModal, setShowAuthModal] = useState(false);
    const [isVerifyingIdentity, setIsVerifyingIdentity] = useState(false);

    // Profile & Personalization State
    const [isProfileModalOpen, setProfileModalOpen] = useState(false);
    const [isPersonalizationModalOpen, setPersonalizationModalOpen] = useState(false);
    const [showLoginModal, setShowLoginModal] = useState(false);

    const [selectedArticle, setSelectedArticle] = useState<NewsArticle | null>(null);
    const [isChatOpen, setChatOpen] = useState(false);
    const [isLiveAgentOpen, setLiveAgentOpen] = useState(false);
    const [isAudioGenOpen, setAudioGenOpen] = useState(false);
    const [searchResults, setSearchResults] = useState<any>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [articles, setArticles] = useState<NewsArticle[]>(initialArticles);

    // Pagination & Infinite Scroll
    const [isLoadingMore, setIsLoadingMore] = useState(false);
    const [preferences, setPreferences] = useState<{categories: string[], sources: string[]}>({ categories: [], sources: [] });
    const [viewMode, setViewMode] = useState<'grid' | 'reels' | 'club' | 'admin'>('grid');

    const [savedArticles, setSavedArticles] = useState<Set<number>>(new Set());
    const [showSavedOnly, setShowSavedOnly] = useState(false);

    // Scroll Logic States
    const [scrollDirection, setScrollDirection] = useState<'up' | 'down'>('up');
    const [isAtTop, setIsAtTop] = useState(true);
    const [isScrolling, setIsScrolling] = useState(false);
    const lastScrollY = useRef(0);
    const scrollTimeout = useRef<number | null>(null);

    const observer = useRef<IntersectionObserver | null>(null);

    // Auth & Data Sync
    const checkUserProfile = useCallback(async (user: User) => {
        const profile = await getUserProfile(user.uid);
        if (profile) {
            setUserProfile(profile);
            setShowAuthModal(false);
            // Log login time
            await logUserLogin(user.uid);
        } else {
            // Profile doesn't exist - Trigger signup flow
            setShowAuthModal(true);
        }
    }, []);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (user) => {
            setCurrentUser(user);
            if (user) {
                setIsVerifyingIdentity(true); // START LOADING

                // Check if profile exists in DB
                await checkUserProfile(user);

                // Load Cloud Data
                const userData = await loadUserData(user.uid);
                if (userData) {
                    if (userData.savedArticles) setSavedArticles(new Set(userData.savedArticles));
                    if (userData.preferences) setPreferences(userData.preferences);
                }

                setIsVerifyingIdentity(false); // STOP LOADING
            } else {
                // Load Local Data
                try {
                    const saved = localStorage.getItem('savedArticles');
                    if (saved) setSavedArticles(new Set(JSON.parse(saved)));
                } catch { setSavedArticles(new Set()); }
                setIsVerifyingIdentity(false);
            }
        });
        return () => unsubscribe();
    }, [checkUserProfile]);

    const handleProfileComplete = async () => {
        if (currentUser) {
            await checkUserProfile(currentUser);
        }
    };

    // Helper to ensure mutual exclusivity
    const openTool = useCallback((tool: 'chat' | 'live' | 'audio') => {
        setChatOpen(tool === 'chat');
        setLiveAgentOpen(tool === 'live');
        setAudioGenOpen(tool === 'audio');
        setSelectedArticle(null); // Close article if open
        setPersonalizationModalOpen(false); // Close personalization
        setProfileModalOpen(false);
    }, []);

    const closeAll = useCallback(() => {
        setChatOpen(false);
        setLiveAgentOpen(false);
        setAudioGenOpen(false);
        setSelectedArticle(null);
        setPersonalizationModalOpen(false);
        setProfileModalOpen(false);
    }, []);

    const allCategories = [...new Set(articles.map(a => a.category))];
    const allSources = [...new Set(articles.map(a => a.source))];

    useEffect(() => {
        if (!currentUser) {
            localStorage.setItem('savedArticles', JSON.stringify(Array.from(savedArticles)));
        }
    }, [savedArticles, currentUser]);

    const toggleSaveArticle = useCallback(async (articleId: number) => {
        const isSaving = !savedArticles.has(articleId);

        setSavedArticles(prev => {
            const newSet = new Set(prev);
            if (newSet.has(articleId)) newSet.delete(articleId);
            else newSet.add(articleId);
            return newSet;
        });

        if (currentUser) {
            await toggleCloudSavedArticle(currentUser.uid, articleId, isSaving);
        }
    }, [savedArticles, currentUser]);

    const fetchMoreArticles = useCallback(async () => {
        if (isLoadingMore) return;
        // LOGIN RESTRICTION FOR INFINITE SCROLL REMOVED

        setIsLoadingMore(true);
        try {
            const newRawArticles = await generateFuturisticArticles(4);
            const newArticles: NewsArticle[] = newRawArticles.map((a, index) => ({
                id: Date.now() + index,
                ...a,
                isSummaryLoading: false 
            }));
            setArticles(prev => [...prev, ...newArticles]);
        } catch (e) {
            console.error("Failed to load more articles", e);
        } finally {
            setIsLoadingMore(false);
        }
    }, [isLoadingMore]);

    const lastArticleElementRef = useCallback((node: HTMLDivElement) => {
        if (isLoadingMore || showSavedOnly) return;
        // If not logged in, we don't trigger load more (REMOVED)

        if (observer.current) observer.current.disconnect();
        observer.current = new IntersectionObserver(entries => {
            if (entries[0].isIntersecting) {
                fetchMoreArticles();
            }
        });
        if (node) observer.current.observe(node);
    }, [isLoadingMore, showSavedOnly, fetchMoreArticles]);

    const handleCardClick = useCallback((article: NewsArticle) => {
        closeAll();
        setSelectedArticle(article);
    }, [closeAll]);

    const handleCloseModal = () => {
        setSelectedArticle(null);
    };

    const handleCloseSearch = () => {
        setSearchResults(null);
        setIsSearching(false);
    };

    const handleSearch = useCallback(async (query: string) => {
        if (!query.trim()) return;
        setIsSearching(true);
        try {
            const results = await searchWithGoogle(query);
            setSearchResults(results);
        } catch (error) {
            console.error('Search failed:', error);
            setSearchResults({ text: 'An error occurred during the search.', sources: [] });
        } finally {
            setIsSearching(false);
        }
    }, []);

    const handleSavePreferences = async (newPreferences: {categories: string[], sources: string[]}) => {
        setPreferences(newPreferences);
        if (currentUser) {
            await saveUserPreferences(currentUser.uid, newPreferences);
        }
    };

    const handleMainScroll = (e: React.UIEvent<HTMLElement>) => {
        const currentScrollY = e.currentTarget.scrollTop;

        // Determine Direction
        if (currentScrollY > lastScrollY.current && currentScrollY > 50) {
            setScrollDirection('down');
        } else if (currentScrollY < lastScrollY.current) {
            setScrollDirection('up');
        }

        // Determine At Top
        setIsAtTop(currentScrollY < 20);

        // Determine Scrolling State
        setIsScrolling(true);
        if (scrollTimeout.current) {
            window.clearTimeout(scrollTimeout.current);
        }
        scrollTimeout.current = window.setTimeout(() => {
            setIsScrolling(false);
        }, 150);

        lastScrollY.current = currentScrollY;
    };

    const baseFilteredArticles = articles.filter(article => {
        const categoryMatch = preferences.categories.length === 0 || preferences.categories.includes(article.category);
        const sourceMatch = preferences.sources.length === 0 || preferences.sources.includes(article.source);
        return categoryMatch && sourceMatch;
    });

    const displayedArticles = showSavedOnly
        ? articles.filter(a => savedArticles.has(a.id))
        : baseFilteredArticles;

    // IF VERIFYING IDENTITY
    if (isVerifyingIdentity) {
        return (
            <div className="h-screen w-full bg-[#050505] flex items-center justify-center">
                <HolographicScanner text="VERIFYING IDENTITY" />
            </div>
        );
    }

    // RENDER LANDING PAGE IF NOT ENTERED YET
    if (showLanding) {
        return <LandingPage onEnterApp={() => setShowLanding(false)} />;
    }

    // Determine Main Content Based on viewMode
    let mainContent;
    if (viewMode === 'reels') {
        mainContent = (
            <div key="reels" className="fixed inset-0 z-50 bg-black animate-page-enter">
                 {/* Glow Trail Effect */}
                 <div className="absolute top-0 bottom-0 w-px bg-gradient-to-b from-transparent via-brand-primary to-transparent opacity-50 blur-[2px] animate-scan-sweep pointer-events-none z-[60]"></div>
                <ErrorBoundary componentName="ReelsView">
                    <ReelsView 
                        articles={displayedArticles} 
                        onCardClick={handleCardClick}
                        onToggleSave={toggleSaveArticle}
                        savedArticles={savedArticles}
                        onLoadMore={fetchMoreArticles}
                        isLoadingMore={isLoadingMore}
                        onExitReels={() => setViewMode('grid')}
                    />
                </ErrorBoundary>
            </div>
        );
    } else if (viewMode === 'club') {
        mainContent = currentUser ? (
            <div key="club" className="flex-grow relative z-10 animate-page-enter pt-16">
                <ErrorBoundary componentName="ClubDashboard">
                    <ClubDashboard user={currentUser} />
                </ErrorBoundary>
            </div>
        ) : (
            <div className="flex-grow flex items-center justify-center pt-16">
                <p className="text-white">Please Login to access Club Features.</p>
            </div>
        );
    } else if (viewMode === 'admin') {
        mainContent = (currentUser && userProfile?.role === 'admin') ? (
            <div key="admin" className="flex-grow relative z-10 animate-page-enter pt-16 h-screen">
                <ErrorBoundary componentName="AdminPanel">
                    <AdminPanel adminUser={userProfile} />
                </ErrorBoundary>
            </div>
        ) : (
            <div className="flex-grow flex items-center justify-center pt-16">
                <p className="text-red-500 font-orbitron">ACCESS DENIED. ADMIN PRIVILEGES REQUIRED.</p>
            </div>
        );
    } else {
        // Grid View
        mainContent = (
            <main 
                key="grid" 
                className="flex-grow overflow-y-auto pb-24 md:pb-4 relative z-10 animate-page-enter pt-16"
                onScroll={handleMainScroll}
            >
                {/* Glow Trail Effect */}
                <div className="absolute top-0 bottom-0 w-px bg-gradient-to-b from-transparent via-brand-primary to-transparent opacity-50 blur-[2px] animate-scan-sweep pointer-events-none z-[60]"></div>

                <div className="container mx-auto">
                    <HomeView 
                        articles={displayedArticles}
                        onArticleClick={handleCardClick}
                        onToggleSave={toggleSaveArticle}
                        savedArticles={savedArticles}
                        onOpenChat={() => openTool('chat')}
                        onOpenLive={() => openTool('live')}
                        onOpenAudio={() => openTool('audio')}
                        onViewReels={() => setViewMode('reels')}
                        onSearch={handleSearch}
                        isUserLoggedIn={!!currentUser} // PASS USER STATUS
                        onTriggerLogin={() => setShowLoginModal(true)}
                    />

                    {/* Infinite Scroll Trigger - Always Active */}
                    <div ref={lastArticleElementRef} className="h-10 w-full"></div>

                    {isLoadingMore && !showSavedOnly && (
                        <div className="flex justify-center items-center py-8">
                            <HolographicScanner text="GENERATING NEW INTEL" />
                        </div>
                    )}
                </div>
            </main>
        );
    }

    return (
        <div className="h-full bg-brand-bg font-sans flex flex-col relative overflow-hidden">
            <ParticleBackground />

            {/* Show Header only if NOT in Reels view mode */}
            {viewMode !== 'reels' && (
                <Header 
                    onSearch={handleSearch} 
                    isSearching={isSearching} 
                    onPersonalizeClick={() => { 
                        closeAll(); 
                        // PROFILE PROTECTION
                        if (currentUser) {
                            setProfileModalOpen(true);
                        } else {
                            setShowLoginModal(true);
                        }
                    }}
                    viewMode={viewMode}
                    onToggleViewMode={(mode) => setViewMode(mode)}
                    showSavedOnly={showSavedOnly}
                    onToggleShowSaved={() => setShowSavedOnly(prev => !prev)}
                    onOpenChat={() => openTool('chat')}
                    scrollDirection={scrollDirection}
                    isAtTop={isAtTop}
                />
            )}

            {mainContent}

            {/* Auth Modal for New Users */}
            {showAuthModal && currentUser && (
                <AuthModal user={currentUser} onComplete={handleProfileComplete} />
            )}

            {/* Login Modal */}
            {showLoginModal && (
                <LoginModal onClose={() => setShowLoginModal(false)} onLoginSuccess={() => setShowLoginModal(false)} />
            )}

            {selectedArticle && (
                <ErrorBoundary componentName="ArticleModal">
                    <ArticleModal 
                        article={selectedArticle} 
                        onClose={handleCloseModal}
                        onToggleSave={toggleSaveArticle}
                        isSaved={savedArticles.has(selectedArticle.id)}
                    />
                </ErrorBoundary>
            )}

            {/* Search Modal */}
            {(searchResults || isSearching) && (
                <SearchResultsModal 
                    result={searchResults || { text: '', sources: [] }} 
                    onClose={handleCloseSearch} 
                    isLoading={isSearching} 
                />
            )}

            {/* Profile Modal */}
            {isProfileModalOpen && currentUser && (
                <ProfileModal 
                    user={currentUser} 
                    onClose={() => setProfileModalOpen(false)}
                    onOpenPersonalization={() => { setProfileModalOpen(false); setPersonalizationModalOpen(true); }}
                />
            )}

            {/* Personalization Modal */}
            {isPersonalizationModalOpen && (
                <PersonalizationModal
                    allCategories={allCategories}
                    allSources={allSources}
                    currentPreferences={preferences}
                    onSave={handleSavePreferences}
                    onClose={() => setPersonalizationModalOpen(false)}
                />
            )}

            {/* Audio Modal */}
            {isAudioGenOpen && (
                <ErrorBoundary componentName="AudioGenerationModal">
                    <AudioGenerationModal 
                        articles={articles} 
                        onClose={() => setAudioGenOpen(false)} 
                        user={currentUser} // PASS USER
                        onLoginRequest={() => { /* Guest access allowed */ }}
                    />
                </ErrorBoundary>
            )}

            {/* Desktop FABs - Hide in reels mode */}
            {viewMode !== 'reels' && viewMode !== 'admin' && (
                <div className="hidden md:flex fixed bottom-6 right-6 flex-col items-center gap-6 z-50">
                     <button
                        onClick={() => openTool('audio')}
                        className={`
                            w-16 h-16 rounded-full flex items-center justify-center text-white 
                            bg-white/5 border border-brand-secondary/50 backdrop-blur-xl
                            shadow-[0_0_20px_rgba(123,47,255,0.4)]
                            hover:bg-brand-secondary hover:shadow-[0_0_30px_#7B2FFF] hover:scale-110 
                            transition-all duration-300
                            ${isAudioGenOpen ? 'ring-2 ring-white/50 bg-brand-secondary' : ''}
                        `}
                        aria-label="Open Audio Synthesis"
                    >
                        <SoundWaveIcon className="w-8 h-8" />
                    </button>
                    <button
                        onClick={() => openTool('live')}
                        className={`
                            w-16 h-16 rounded-full flex items-center justify-center text-white 
                            bg-white/5 border border-brand-accent/50 backdrop-blur-xl
                            shadow-[0_0_20px_rgba(40,255,211,0.4)]
                            hover:bg-brand-accent hover:text-black hover:shadow-[0_0_30px_#28FFD3] hover:scale-110 
                            transition-all duration-300 animate-pulse-glow
                            ${isLiveAgentOpen ? 'ring-2 ring-white/50 bg-brand-accent text-black' : ''}
                        `}
                        aria-label="Open Live Agent"
                    >
                        <MicIcon className="w-8 h-8" />
                    </button>
                    <button
                        onClick={() => setChatOpen(prev => !prev ? true : false)}
                        className={`
                            w-16 h-16 rounded-full flex items-center justify-center text-white 
                            bg-white/5 border border-brand-primary/50 backdrop-blur-xl
                            shadow-[0_0_20px_rgba(58,190,254,0.4)]
                            hover:bg-brand-primary hover:text-black hover:shadow-[0_0_30px_#3ABEFE] hover:scale-110 
                            transition-all duration-300
                            ${isChatOpen ? 'ring-2 ring-white/50 bg-brand-primary text-black' : ''}
                        `}
                        aria-label="Toggle Chat"
                    >
                        <BoltIcon className="w-8 h-8" />
                    </button>
                </div>
            )}

            {/* Bottom Nav - Hide in reels mode */}
            {viewMode !== 'reels' && (
                <BottomNav 
                    viewMode={(viewMode === 'club' || viewMode === 'admin') ? 'grid' : viewMode}
                    onChangeView={(mode) => setViewMode(mode)}
                    onOpenExplore={() => {
                        document.getElementById('trending-section')?.scrollIntoView({ behavior: 'smooth' });
                    }}
                    onOpenChat={() => openTool('chat')}
                    onOpenProfile={() => { 
                        closeAll(); 
                        if (currentUser) setProfileModalOpen(true);
                        else setShowLoginModal(true);
                    }}
                    isScrolling={isScrolling}
                />
            )}

            <ErrorBoundary componentName="ChatBot">
                <ChatBot 
                    isOpen={isChatOpen} 
                    onClose={() => setChatOpen(false)} 
                    user={currentUser} // PASS USER
                />
            </ErrorBoundary>
            {isLiveAgentOpen && (
                <ErrorBoundary componentName="LiveAgent">
                    <LiveAgent onClose={() => setLiveAgentOpen(false)} />
                </ErrorBoundary>
            )}
        </div>
    );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { streamChatResponse, generateImageFromPrompt, resetChat } from '../services/geminiService';
import { CloseIcon, SendIcon, ImageIcon, MicIcon, StopIcon } from './icons';
import { ThinkingBubble } from './Loaders';
import { Part } from '@google/genai';
import { User } from 'firebase/auth';

interface ChatBotProps {
    isOpen: boolean;
    onClose: () => void;
    user: User | null;
}

const BotAvatar = () => (
    <div className="w-10 h-10 rounded-full bg-[#0a0a0a] border border-brand-primary flex items-center justify-center overflow-hidden shrink-0 shadow-[0_0_15px_#3ABEFE] relative group">
        <div className="absolute inset-0 bg-brand-primary/20 animate-pulse rounded-full"></div>
        <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-brand-primary relative z-10">
            <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="1.5" />
            <path d="M7 13L10 16L17 9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
            <circle cx="9" cy="9" r="1" fill="currentColor" className="animate-ping" />
            <circle cx="15" cy="9" r="1" fill="currentColor" className="animate-ping" style={{ animationDelay: '0.5s' }} />
        </svg>
    </div>
);

const ChatBot: React.FC<ChatBotProps> = ({ isOpen, onClose, user }) => {
    const [messages, setMessages] = useState<ChatMessage[]>([
        { id: 'initial', text: 'Greetings. I am your Neural Assistant. Ask me anything regarding News, Science, or Technology.', sender: 'bot' }
    ]);
    const [input, setInput] = useState('');
    const [mode, setMode] = useState<'chat' | 'image'>('chat');
    const [isRecording, setIsRecording] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const audioChunksRef = useRef<Blob[]>([]);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(scrollToBottom, [messages]);

    useEffect(() => {
        if (isOpen) {
             resetChat();
             if(messages.length === 0 || messages[0].id !== 'initial') {
                 setMessages([ { id: 'initial', text: 'Greetings. I am your Neural Assistant. Ask me anything regarding News, Science, or Technology.', sender: 'bot' } ]);
             }
            setError(null);
        } else {
            setInput('');
            setMode('chat');
            setIsRecording(false);
            if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
                mediaRecorderRef.current.stop();
            }
        }
    }, [isOpen]);

    const startRecording = async () => {
        setError(null);
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const mediaRecorder = new MediaRecorder(stream);
            mediaRecorderRef.current = mediaRecorder;
            audioChunksRef.current = [];

            mediaRecorder.ondataavailable = (event) => {
                if (event.data.size > 0) {
                    audioChunksRef.current.push(event.data);
                }
            };

            mediaRecorder.onstop = async () => {
                const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' }); 
                const reader = new FileReader();
                reader.readAsDataURL(audioBlob);
                reader.onloadend = async () => {
                    const base64Data = (reader.result as string).split(',')[1];
                    await handleVoiceMessage(base64Data);
                };
                stream.getTracks().forEach(track => track.stop());
            };

            mediaRecorder.start();
            setIsRecording(true);
        } catch (err) {
            console.error("Error accessing microphone:", err);
            setError("Could not access microphone.");
        }
    };

    const stopRecording = () => {
        if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
            mediaRecorderRef.current.stop();
            setIsRecording(false);
        }
    };

    const handleVoiceMessage = async (base64Audio: string) => {
        const userMessage: ChatMessage = { id: Date.now().toString(), text: "🎤 [Audio Message]", sender: 'user' };
        const botMessageId = (Date.now() + 1).toString();
        const botMessage: ChatMessage = { id: botMessageId, sender: 'bot', isLoading: true };

        setMessages(prev => [...prev, userMessage, botMessage]);

        try {
            const audioPart: Part = {
                inlineData: {
                    mimeType: 'audio/webm',
                    data: base64Audio
                }
            };
            const parts: Part[] = [ audioPart, { text: "Listen to this audio and respond helpfuly." } ];

            await streamChatResponse(parts, (chunk) => {
                setMessages(prev => prev.map(msg => 
                    msg.id === botMessageId 
                        ? { ...msg, text: (msg.text || '') + chunk, isLoading: false } 
                        : msg
                ));
            });
        } catch (err) {
             setMessages(prev => prev.map(msg => 
                msg.id === botMessageId 
                    ? { ...msg, text: "Sorry, I couldn't process the audio.", isLoading: false, isError: true } 
                    : msg
            ));
        }
    };

    const handleChat = async () => {
        const userMessage: ChatMessage = { id: Date.now().toString(), text: input, sender: 'user' };
        const botMessageId = (Date.now() + 1).toString();
        const botMessage: ChatMessage = { id: botMessageId, sender: 'bot', isLoading: true };

        setMessages(prev => [...prev, userMessage, botMessage]);

        await streamChatResponse(input, (chunk) => {
            setMessages(prev => prev.map(msg => 
                msg.id === botMessageId 
                    ? { ...msg, text: (msg.text || '') + chunk, isLoading: false } 
                    : msg
            ));
        });
    }

    const handleImageGeneration = async () => {
        const userMessage: ChatMessage = { id: Date.now().toString(), text: `Generate an image of: ${input}`, sender: 'user' };
        const botMessageId = (Date.now() + 1).toString();
        const botMessage: ChatMessage = { id: botMessageId, sender: 'bot', isLoading: true };

        setMessages(prev => [...prev, userMessage, botMessage]);

        // RESTRICTION REMOVED for guest access

        try {
            const imageUrl = await generateImageFromPrompt(input);
             setMessages(prev => prev.map(msg => 
                msg.id === botMessageId 
                    ? { ...msg, imageUrl, isLoading: false } 
                    : msg
            ));
        } catch(error) {
             setMessages(prev => prev.map(msg => 
                msg.id === botMessageId 
                    ? { 
                        ...msg, 
                        text: error instanceof Error ? error.message : "Image generation failed.", 
                        isLoading: false,
                        isError: true 
                      } 
                    : msg
            ));
        }
    }

    const handleSend = async () => {
        if (input.trim() === '') return;
        setInput('');

        if (mode === 'image') {
            await handleImageGeneration();
        } else {
            await handleChat();
        }
    };

    const getPlaceholder = () => {
        if (isRecording) return 'Listening...';
        switch(mode) {
            case 'image': return 'Describe an image to create...';
            default: return 'Type message...';
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed bottom-24 right-0 left-0 md:left-auto md:right-6 w-full md:w-[450px] h-[70vh] z-40 animate-slide-up px-3 md:px-0">
            {/* FLOATING GLASS PANEL */}
            <div className="
                bg-[#050505]/80 backdrop-blur-2xl 
                rounded-[22px] 
                shadow-[0_0_50px_rgba(58,190,254,0.15)] 
                flex flex-col h-full 
                border border-white/10 ring-1 ring-white/5 
                overflow-hidden relative
            ">
                {/* Holographic Texture Overlay */}
                <div className="absolute inset-0 bg-grid-pattern opacity-[0.05] pointer-events-none"></div>

                <header className="p-4 border-b border-white/5 flex justify-between items-center bg-white/5 relative z-10">
                    <div className="flex items-center gap-3">
                        <BotAvatar />
                        <div>
                            <h2 className="font-orbitron text-sm text-brand-primary font-bold tracking-wider">NEWS REPORTER</h2>
                            <div className="flex items-center gap-1.5">
                                <span className="w-1.5 h-1.5 bg-brand-accent rounded-full animate-pulse shadow-[0_0_5px_#28FFD3]"></span>
                                <span className="text-[9px] text-brand-text-muted uppercase tracking-widest">System Active</span>
                            </div>
                        </div>
                    </div>
                    <button onClick={onClose} className="text-brand-text-muted hover:text-brand-primary transition-colors p-2 hover:bg-white/5 rounded-full border border-transparent hover:border-white/10">
                        <CloseIcon />
                    </button>
                </header>

                {error && <div className="bg-red-900/40 border-b border-red-500/50 text-red-200 text-xs p-2 text-center font-mono relative z-10">system_alert: {error}</div>}

                <div className="flex-grow p-4 overflow-y-auto space-y-4 scrollbar-thin scrollbar-thumb-brand-primary/20 scrollbar-track-transparent relative z-10">
                    {messages.map(msg => (
                        <div key={msg.id} className={`flex gap-3 ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                            {msg.sender === 'bot' && <div className="pt-1"><BotAvatar /></div>}

                            {/* AI MESSAGE BOXES */}
                            <div className={`
                                max-w-[85%] px-5 py-3.5 
                                backdrop-blur-md border transition-all duration-300 relative overflow-hidden group
                                ${
                                    msg.isError 
                                    ? 'bg-red-900/10 border-red-500/40 text-red-200 rounded-2xl shadow-[0_0_15px_rgba(239,68,68,0.2)]'
                                    : msg.sender === 'user' 
                                        ? 'bg-brand-primary/10 border-brand-primary/50 text-white rounded-2xl rounded-br-none shadow-[0_0_15px_rgba(58,190,254,0.2)] animate-pulse-glow' // User Bubble
                                        : 'bg-brand-secondary/10 border-brand-secondary/50 text-brand-text rounded-2xl rounded-bl-none shadow-[0_0_15px_rgba(123,47,255,0.2)] animate-card-enter' // AI Bubble
                                }
                            `}>
                                {/* Light Beam Animation for Bot Messages */}
                                {msg.sender === 'bot' && !msg.isError && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full animate-sheen pointer-events-none"></div>
                                )}

                                {msg.isLoading && <ThinkingBubble />}

                                {msg.isError && (
                                    <div className="flex items-center gap-2 mb-2 border-b border-red-500/30 pb-1">
                                        <div className="w-2 h-2 bg-red-500 rounded-full animate-ping"></div>
                                        <span className="font-orbitron text-[10px] font-bold text-red-400 tracking-widest">SYSTEM FAILURE</span>
                                    </div>
                                )}

                                {msg.text && <p className={`whitespace-pre-wrap text-sm leading-relaxed font-light ${msg.isError ? 'font-mono text-xs opacity-80' : ''}`}>{msg.text}</p>}

                                {msg.imageUrl && (
                                    <div className="mt-2 relative group/img rounded-xl overflow-hidden border border-brand-primary/40 shadow-[0_0_20px_rgba(58,190,254,0.2)]">
                                        <img src={msg.imageUrl} alt="Generated" className="w-full h-auto transition-transform duration-700 group-hover/img:scale-105" />
                                        <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent opacity-0 group-hover/img:opacity-100 transition-opacity flex items-end p-3">
                                            <span className="text-[10px] text-brand-primary font-orbitron tracking-widest border border-brand-primary/50 px-2 py-1 rounded bg-black/50 backdrop-blur-md">GENERATED_ASSET</span>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                    <div ref={messagesEndRef} />
                </div>

                <footer className="p-3 border-t border-white/5 bg-white/5 backdrop-blur-lg relative z-10">
                    <div className="flex items-center gap-2 bg-[#0a0a0a] border border-white/10 rounded-full p-1.5 pl-3 focus-within:border-brand-primary/50 transition-colors shadow-inner">
                         <button 
                            onClick={() => setMode(m => m === 'image' ? 'chat' : 'image')} 
                            className={`p-2 rounded-full transition-all duration-300 ${mode === 'image' ? 'bg-brand-secondary text-white shadow-[0_0_15px_#7B2FFF]' : 'text-brand-text-muted hover:text-brand-text hover:bg-white/5'}`}
                            title="Toggle Image Mode"
                        >
                            <ImageIcon className="h-5 w-5" />
                        </button>

                        <input
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                            placeholder={getPlaceholder()}
                            disabled={isRecording}
                            className="flex-grow bg-transparent border-none focus:ring-0 text-sm text-brand-text placeholder-brand-text-muted/30 px-2 font-light tracking-wide"
                        />

                        {mode === 'chat' && (
                            <button 
                                onClick={isRecording ? stopRecording : startRecording} 
                                className={`
                                    p-2 rounded-full transition-all duration-300 border
                                    ${isRecording 
                                        ? 'bg-brand-accent text-black animate-vibrate ring-2 ring-brand-accent shadow-[0_0_20px_#28FFD3] border-brand-accent' 
                                        : 'bg-transparent border-transparent text-brand-text-muted hover:text-brand-accent hover:border-brand-accent/50 hover:bg-white/5'}
                                `}
                                title="Voice Input"
                            >
                                {isRecording ? <StopIcon className="h-5 w-5" /> : <MicIcon className="h-5 w-5" />}
                            </button>
                        )}

                        <button 
                            onClick={handleSend} 
                            disabled={isRecording || !input.trim()} 
                            className="
                                group relative overflow-hidden
                                p-2.5 rounded-full text-white 
                                bg-white/5 border border-brand-primary/50
                                transition-all hover:bg-brand-primary/20 hover:border-brand-primary hover:shadow-[0_0_15px_rgba(58,190,254,0.5)]
                                active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed
                            "
                        >
                             <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:animate-sheen z-0"></div>
                            <SendIcon />
                        </button>
                    </div>
                </footer>
            </div>
        </div>
    );
};

