const App = () => {
    // New State for Landing Page
    const [showLanding, setShowLanding] = useState(true);
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
    const [showAuthModal, setShowAuthModal] = useState(false);
    const [isVerifyingIdentity, setIsVerifyingIdentity] = useState(false);

    // Profile & Personalization State
    const [isProfileModalOpen, setProfileModalOpen] = useState(false);
    const [isPersonalizationModalOpen, setPersonalizationModalOpen] = useState(false);
    const [showLoginModal, setShowLoginModal] = useState(false);

    const [selectedArticle, setSelectedArticle] = useState<NewsArticle | null>(null);
    const [isChatOpen, setChatOpen] = useState(false);
    const [isLiveAgentOpen, setLiveAgentOpen] = useState(false);
    const [isAudioGenOpen, setAudioGenOpen] = useState(false);
    const [searchResults, setSearchResults] = useState<any>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [articles, setArticles] = useState<NewsArticle[]>(initialArticles);

    // Pagination & Infinite Scroll
    const [isLoadingMore, setIsLoadingMore] = useState(false);
    const [preferences, setPreferences] = useState<{categories: string[], sources: string[]}>({ categories: [], sources: [] });
    const [viewMode, setViewMode] = useState<'grid' | 'reels' | 'admin'>('grid');

    const [savedArticles, setSavedArticles] = useState<Set<number>>(new Set());
    const [showSavedOnly, setShowSavedOnly] = useState(false);

    // Scroll Logic States
    const [scrollDirection, setScrollDirection] = useState<'up' | 'down'>('up');
    const [isAtTop, setIsAtTop] = useState(true);
    const [isScrolling, setIsScrolling] = useState(false);
    const lastScrollY = useRef(0);
    const scrollTimeout = useRef<number | null>(null);

    const observer = useRef<IntersectionObserver | null>(null);

    // Auth & Data Sync
    const checkUserProfile = useCallback(async (user: User) => {
        const profile = await getUserProfile(user.uid);
        if (profile) {
            setUserProfile(profile);
            setShowAuthModal(false);
            // Log login time
            await logUserLogin(user.uid);
        } else {
            // Profile doesn't exist - Trigger signup flow
            setShowAuthModal(true);
        }
    }, []);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (user) => {
            setCurrentUser(user);
            if (user) {
                setIsVerifyingIdentity(true); // START LOADING

                // Check if profile exists in DB
                await checkUserProfile(user);

                // Load Cloud Data
                const userData = await loadUserData(user.uid);
                if (userData) {
                    if (userData.savedArticles) setSavedArticles(new Set(userData.savedArticles));
                    if (userData.preferences) setPreferences(userData.preferences);
                }

                setIsVerifyingIdentity(false); // STOP LOADING
            } else {
                // Load Local Data
                try {
                    const saved = localStorage.getItem('savedArticles');
                    if (saved) setSavedArticles(new Set(JSON.parse(saved)));
                } catch { setSavedArticles(new Set()); }
                setIsVerifyingIdentity(false);
            }
        });
        return () => unsubscribe();
    }, [checkUserProfile]);

    const handleProfileComplete = async () => {
        if (currentUser) {
            await checkUserProfile(currentUser);
        }
    };

    // Helper to ensure mutual exclusivity
    const openTool = useCallback((tool: 'chat' | 'live' | 'audio') => {
        setChatOpen(tool === 'chat');
        setLiveAgentOpen(tool === 'live');
        setAudioGenOpen(tool === 'audio');
        setSelectedArticle(null); // Close article if open
        setPersonalizationModalOpen(false); // Close personalization
        setProfileModalOpen(false);
    }, []);

    const closeAll = useCallback(() => {
        setChatOpen(false);
        setLiveAgentOpen(false);
        setAudioGenOpen(false);
        setSelectedArticle(null);
        setPersonalizationModalOpen(false);
        setProfileModalOpen(false);
    }, []);

    const allCategories = [...new Set(articles.map(a => a.category))];
    const allSources = [...new Set(articles.map(a => a.source))];

    useEffect(() => {
        if (!currentUser) {
            localStorage.setItem('savedArticles', JSON.stringify(Array.from(savedArticles)));
        }
    }, [savedArticles, currentUser]);

    const toggleSaveArticle = useCallback(async (articleId: number) => {
        const isSaving = !savedArticles.has(articleId);

        setSavedArticles(prev => {
            const newSet = new Set(prev);
            if (newSet.has(articleId)) newSet.delete(articleId);
            else newSet.add(articleId);
            return newSet;
        });

        if (currentUser) {
            await toggleCloudSavedArticle(currentUser.uid, articleId, isSaving);
        }
    }, [savedArticles, currentUser]);

    const fetchMoreArticles = useCallback(async () => {
        if (isLoadingMore) return;
        // LOGIN RESTRICTION FOR INFINITE SCROLL REMOVED

        setIsLoadingMore(true);
        try {
            const newRawArticles = await generateFuturisticArticles(4);
            const newArticles: NewsArticle[] = newRawArticles.map((a, index) => ({
                id: Date.now() + index,
                ...a,
                isSummaryLoading: false 
            }));
            setArticles(prev => [...prev, ...newArticles]);
        } catch (e) {
            console.error("Failed to load more articles", e);
        } finally {
            setIsLoadingMore(false);
        }
    }, [isLoadingMore]);

    const lastArticleElementRef = useCallback((node: HTMLDivElement) => {
        if (isLoadingMore || showSavedOnly) return;
        // If not logged in, we don't trigger load more (REMOVED)

        if (observer.current) observer.current.disconnect();
        observer.current = new IntersectionObserver(entries => {
            if (entries[0].isIntersecting) {
                fetchMoreArticles();
            }
        });
        if (node) observer.current.observe(node);
    }, [isLoadingMore, showSavedOnly, fetchMoreArticles]);

    const handleCardClick = useCallback((article: NewsArticle) => {
        closeAll();
        setSelectedArticle(article);
    }, [closeAll]);

    const handleCloseModal = () => {
        setSelectedArticle(null);
    };

    const handleCloseSearch = () => {
        setSearchResults(null);
        setIsSearching(false);
    };

    const handleSearch = useCallback(async (query: string) => {
        if (!query.trim()) return;
        setIsSearching(true);
        try {
            const results = await searchWithGoogle(query);
            setSearchResults(results);
        } catch (error) {
            console.error('Search failed:', error);
            setSearchResults({ text: 'An error occurred during the search.', sources: [] });
        } finally {
            setIsSearching(false);
        }
    }, []);

    const handleSavePreferences = async (newPreferences: {categories: string[], sources: string[]}) => {
        setPreferences(newPreferences);
        if (currentUser) {
            await saveUserPreferences(currentUser.uid, newPreferences);
        }
    };

    const handleMainScroll = (e: React.UIEvent<HTMLElement>) => {
        const currentScrollY = e.currentTarget.scrollTop;

        // Determine Direction
        if (currentScrollY > lastScrollY.current && currentScrollY > 50) {
            setScrollDirection('down');
        } else if (currentScrollY < lastScrollY.current) {
            setScrollDirection('up');
        }

        // Determine At Top
        setIsAtTop(currentScrollY < 20);

        // Determine Scrolling State
        setIsScrolling(true);
        if (scrollTimeout.current) {
            window.clearTimeout(scrollTimeout.current);
        }
        scrollTimeout.current = window.setTimeout(() => {
            setIsScrolling(false);
        }, 150);

        lastScrollY.current = currentScrollY;
    };

    const baseFilteredArticles = articles.filter(article => {
        const categoryMatch = preferences.categories.length === 0 || preferences.categories.includes(article.category);
        const sourceMatch = preferences.sources.length === 0 || preferences.sources.includes(article.source);
        return categoryMatch && sourceMatch;
    });

    const displayedArticles = showSavedOnly
        ? articles.filter(a => savedArticles.has(a.id))
        : baseFilteredArticles;

    // IF VERIFYING IDENTITY
    if (isVerifyingIdentity) {
        return (
            <div className="h-screen w-full bg-[#050505] flex items-center justify-center">
                <HolographicScanner text="VERIFYING IDENTITY" />
            </div>
        );
    }

    // RENDER LANDING PAGE IF NOT ENTERED YET
    if (showLanding) {
        return <LandingPage onEnterApp={() => setShowLanding(false)} />;
    }

    // Determine Main Content Based on viewMode
    let mainContent;
    if (viewMode === 'reels') {
        mainContent = (
            <div key="reels" className="fixed inset-0 z-50 bg-black animate-page-enter">
                 {/* Glow Trail Effect */}
                 <div className="absolute top-0 bottom-0 w-px bg-gradient-to-b from-transparent via-brand-primary to-transparent opacity-50 blur-[2px] animate-scan-sweep pointer-events-none z-[60]"></div>
                <ErrorBoundary componentName="ReelsView">
                    <ReelsView 
                        articles={displayedArticles} 
                        onCardClick={handleCardClick}
                        onToggleSave={toggleSaveArticle}
                        savedArticles={savedArticles}
                        onLoadMore={fetchMoreArticles}
                        isLoadingMore={isLoadingMore}
                        onExitReels={() => setViewMode('grid')}
                    />
                </ErrorBoundary>
            </div>
        );
    } else if (viewMode === 'admin') {
        mainContent = (currentUser && userProfile?.role === 'admin') ? (
            <div key="admin" className="flex-grow relative z-10 animate-page-enter pt-16 h-screen">
                <ErrorBoundary componentName="AdminPanel">
                    <AdminPanel adminUser={userProfile} />
                </ErrorBoundary>
            </div>
        ) : (
            <div className="flex-grow flex items-center justify-center pt-16">
                <p className="text-red-500 font-orbitron">ACCESS DENIED. ADMIN PRIVILEGES REQUIRED.</p>
            </div>
        );
    } else {
        // Grid View
        mainContent = (
            <main 
                key="grid" 
                className="flex-grow overflow-y-auto pb-24 md:pb-4 relative z-10 animate-page-enter pt-16"
                onScroll={handleMainScroll}
            >
                {/* Glow Trail Effect */}
                <div className="absolute top-0 bottom-0 w-px bg-gradient-to-b from-transparent via-brand-primary to-transparent opacity-50 blur-[2px] animate-scan-sweep pointer-events-none z-[60]"></div>

                <div className="container mx-auto">
                    <HomeView 
                        articles={displayedArticles}
                        onArticleClick={handleCardClick}
                        onToggleSave={toggleSaveArticle}
                        savedArticles={savedArticles}
                        onOpenChat={() => openTool('chat')}
                        onOpenLive={() => openTool('live')}
                        onOpenAudio={() => openTool('audio')}
                        onViewReels={() => setViewMode('reels')}
                        onSearch={handleSearch}
                        isUserLoggedIn={!!currentUser} // PASS USER STATUS
                        onTriggerLogin={() => setShowLoginModal(true)}
                    />

                    {/* Infinite Scroll Trigger OR Login Prompt */}
                    {currentUser ? (
                        <div ref={lastArticleElementRef} className="h-10 w-full"></div>
                    ) : (
                        <div className="py-8 pb-32 flex justify-center w-full">
                            <button 
                                onClick={() => setShowLoginModal(true)}
                                className="px-8 py-3 bg-brand-primary/10 border border-brand-primary/50 text-brand-primary font-orbitron text-xs rounded-full hover:bg-brand-primary hover:text-black transition-all animate-pulse-glow"
                            >
                                LOGIN TO ACCESS FULL DATABASE
                            </button>
                        </div>
                    )}

                    {isLoadingMore && !showSavedOnly && (
                        <div className="flex justify-center items-center py-8">
                            <HolographicScanner text="GENERATING NEW INTEL" />
                        </div>
                    )}
                </div>
            </main>
        );
    }

    return (
        <div className="h-full bg-brand-bg font-sans flex flex-col relative overflow-hidden">
            <ParticleBackground />

            {/* Show Header only if NOT in Reels view mode */}
            {viewMode !== 'reels' && (
                <Header 
                    onSearch={handleSearch} 
                    isSearching={isSearching} 
                    onPersonalizeClick={() => { 
                        closeAll(); 
                        // PROFILE PROTECTION
                        if (currentUser) {
                            setProfileModalOpen(true);
                        } else {
                            setShowLoginModal(true);
                        }
                    }}
                    viewMode={viewMode}
                    onToggleViewMode={(mode) => setViewMode(mode)}
                    showSavedOnly={showSavedOnly}
                    onToggleShowSaved={() => setShowSavedOnly(prev => !prev)}
                    onOpenChat={() => openTool('chat')}
                    scrollDirection={scrollDirection}
                    isAtTop={isAtTop}
                />
            )}

            {mainContent}

            {/* Auth Modal for New Users */}
            {showAuthModal && currentUser && (
                <AuthModal user={currentUser} onComplete={handleProfileComplete} />
            )}

            {/* Login Modal */}
            {showLoginModal && (
                <LoginModal onClose={() => setShowLoginModal(false)} onLoginSuccess={() => setShowLoginModal(false)} />
            )}

            {selectedArticle && (
                <ErrorBoundary componentName="ArticleModal">
                    <ArticleModal 
                        article={selectedArticle} 
                        onClose={handleCloseModal}
                        onToggleSave={toggleSaveArticle}
                        isSaved={savedArticles.has(selectedArticle.id)}
                    />
                </ErrorBoundary>
            )}

            {/* Search Modal */}
            {(searchResults || isSearching) && (
                <SearchResultsModal 
                    result={searchResults || { text: '', sources: [] }} 
                    onClose={handleCloseSearch} 
                    isLoading={isSearching} 
                />
            )}

            {/* Profile Modal */}
            {isProfileModalOpen && currentUser && (
                <ProfileModal 
                    user={currentUser} 
                    onClose={() => setProfileModalOpen(false)}
                    onOpenPersonalization={() => { setProfileModalOpen(false); setPersonalizationModalOpen(true); }}
                />
            )}

            {/* Personalization Modal */}
            {isPersonalizationModalOpen && (
                <PersonalizationModal
                    allCategories={allCategories}
                    allSources={allSources}
                    currentPreferences={preferences}
                    onSave={handleSavePreferences}
                    onClose={() => setPersonalizationModalOpen(false)}
                />
            )}

            {/* Audio Modal */}
            {isAudioGenOpen && (
                <ErrorBoundary componentName="AudioGenerationModal">
                    <AudioGenerationModal 
                        articles={articles} 
                        onClose={() => setAudioGenOpen(false)} 
                        user={currentUser} // PASS USER
                        onLoginRequest={() => { /* Guest access allowed */ }}
                    />
                </ErrorBoundary>
            )}

            {/* Desktop FABs - Hide in reels mode */}
            {viewMode !== 'reels' && viewMode !== 'admin' && (
                <div className="hidden md:flex fixed bottom-6 right-6 flex-col items-center gap-6 z-50">
                     <button
                        onClick={() => openTool('audio')}
                        className={`
                            w-16 h-16 rounded-full flex items-center justify-center text-white 
                            bg-white/5 border border-brand-secondary/50 backdrop-blur-xl
                            shadow-[0_0_20px_rgba(123,47,255,0.4)]
                            hover:bg-brand-secondary hover:shadow-[0_0_30px_#7B2FFF] hover:scale-110 
                            transition-all duration-300
                            ${isAudioGenOpen ? 'ring-2 ring-white/50 bg-brand-secondary' : ''}
                        `}
                        aria-label="Open Audio Synthesis"
                    >
                        <SoundWaveIcon className="w-8 h-8" />
                    </button>
                    <button
                        onClick={() => openTool('live')}
                        className={`
                            w-16 h-16 rounded-full flex items-center justify-center text-white 
                            bg-white/5 border border-brand-accent/50 backdrop-blur-xl
                            shadow-[0_0_20px_rgba(40,255,211,0.4)]
                            hover:bg-brand-accent hover:text-black hover:shadow-[0_0_30px_#28FFD3] hover:scale-110 
                            transition-all duration-300 animate-pulse-glow
                            ${isLiveAgentOpen ? 'ring-2 ring-white/50 bg-brand-accent text-black' : ''}
                        `}
                        aria-label="Open Live Agent"
                    >
                        <MicIcon className="w-8 h-8" />
                    </button>
                    <button
                        onClick={() => setChatOpen(prev => !prev ? true : false)}
                        className={`
                            w-16 h-16 rounded-full flex items-center justify-center text-white 
                            bg-white/5 border border-brand-primary/50 backdrop-blur-xl
                            shadow-[0_0_20px_rgba(58,190,254,0.4)]
                            hover:bg-brand-primary hover:text-black hover:shadow-[0_0_30px_#3ABEFE] hover:scale-110 
                            transition-all duration-300
                            ${isChatOpen ? 'ring-2 ring-white/50 bg-brand-primary text-black' : ''}
                        `}
                        aria-label="Toggle Chat"
                    >
                        <BoltIcon className="w-8 h-8" />
                    </button>
                </div>
            )}

            {/* Bottom Nav - Hide in reels mode */}
            {viewMode !== 'reels' && (
                <BottomNav 
                    viewMode={viewMode === 'admin' ? 'grid' : viewMode}
                    onChangeView={(mode) => setViewMode(mode)}
                    onOpenExplore={() => {
                        document.getElementById('trending-section')?.scrollIntoView({ behavior: 'smooth' });
                    }}
                    onOpenChat={() => openTool('chat')}
                    onOpenProfile={() => { 
                        closeAll(); 
                        if (currentUser) setProfileModalOpen(true);
                        else setShowLoginModal(true);
                    }}
                    isScrolling={isScrolling}
                />
            )}

            <ErrorBoundary componentName="ChatBot">
                <ChatBot 
                    isOpen={isChatOpen} 
                    onClose={() => setChatOpen(false)} 
                    user={currentUser} // PASS USER
                />
            </ErrorBoundary>
            {isLiveAgentOpen && (
                <ErrorBoundary componentName="LiveAgent">
                    <LiveAgent onClose={() => setLiveAgentOpen(false)} />
                </ErrorBoundary>
            )}
        </div>
    );
};

export default App;

import React, { useState, useEffect } from 'react';
import { SearchIcon, LogoIcon, HomeIcon, CompassIcon, BoltIcon, ReelsIcon, UserIcon, CloseIcon, MessageSquareIcon, BellIcon } from './icons';
import { auth } from '../services/firebase';
import { onAuthStateChanged, User } from 'firebase/auth';
import { getUserProfile, getUserMessages } from '../services/dbService';
import { UserRole } from '../types';
import NotificationsModal from './NotificationsModal';
import LoginModal from './LoginModal';

interface HeaderProps {
    onSearch: (query: string) => void;
    isSearching: boolean;
    onPersonalizeClick: () => void;
    viewMode: 'grid' | 'reels' | 'admin';
    onToggleViewMode: (mode: 'grid' | 'reels' | 'admin') => void;
    showSavedOnly: boolean;
    onToggleShowSaved: () => void;
    onOpenChat: () => void;
    scrollDirection?: 'up' | 'down';
    isAtTop?: boolean;
}

const Header: React.FC<HeaderProps> = ({ 
    onSearch, 
    isSearching, 
    onPersonalizeClick, 
    viewMode, 
    onToggleViewMode,
    onOpenChat,
    scrollDirection = 'up',
    isAtTop = true
}) => {
    const [query, setQuery] = useState('');
    const [isSearchExpanded, setIsSearchExpanded] = useState(false);
    const [user, setUser] = useState<User | null>(null);
    const [userRole, setUserRole] = useState<UserRole>('user');
    const [showLoginModal, setShowLoginModal] = useState(false);
    const [showNotifications, setShowNotifications] = useState(false);
    const [unreadCount, setUnreadCount] = useState(0);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
            setUser(currentUser);
            if (currentUser) {
                const profile = await getUserProfile(currentUser.uid);
                if (profile) setUserRole(profile.role);

                // Check Notifications
                const msgs = await getUserMessages(currentUser.uid);
                const unread = msgs.filter(m => !m.readBy?.includes(currentUser.uid)).length;
                setUnreadCount(unread);
            } else {
                setUserRole('user');
            }
        });
        return () => unsubscribe();
    }, []);

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        onSearch(query);
        setIsSearchExpanded(false);
    };

    const toggleSearch = () => {
        setIsSearchExpanded(!isSearchExpanded);
    };

    // Helper for button styles
    const navButtonStyle = (isActive: boolean, activeColorClass: string, activeShadowClass: string) => `
        flex items-center gap-2 px-4 py-2 rounded-full transition-all duration-300 border overflow-hidden relative
        font-orbitron text-[10px] font-bold tracking-wider
        ${isActive 
            ? `bg-${activeColorClass}/10 text-${activeColorClass} border-${activeColorClass}/50 shadow-[0_0_15px_${activeShadowClass}]` 
            : 'border-transparent text-brand-text-muted hover:text-white hover:bg-white/5 hover:border-white/10 hover:shadow-[0_0_10px_rgba(255,255,255,0.1)]'
        }
        active:scale-95 active:animate-ripple
    `;

    const isVisible = scrollDirection === 'up' || isAtTop;
    const glassStyle = isAtTop ? 'bg-[#050505]/60 backdrop-blur-lg' : 'bg-[#050505]/90 backdrop-blur-xl shadow-[0_4px_30px_rgba(0,0,0,0.8)]';

    return (
        <>
            {/* Top Bar: Fixed Glassmorphic Style with Scroll Transitions */}
            <header 
                className={`
                    fixed top-0 left-0 right-0 z-40 
                    border-b border-white/5 
                    transition-all duration-500 cubic-bezier(0.16, 1, 0.3, 1)
                    ${glassStyle}
                    ${isVisible ? 'translate-y-0 opacity-100' : '-translate-y-full opacity-0 pointer-events-none'}
                `}
            >
                <div className="container mx-auto px-4 h-16 flex items-center justify-between">

                    {/* 1. NEWS CLUB LOGO */}
                    <div className="flex items-center gap-3 group cursor-pointer" onClick={() => onToggleViewMode('grid')}>
                        <div className="relative">
                            <div className="absolute inset-0 bg-brand-primary/20 blur-lg rounded-full opacity-50 group-hover:opacity-100 transition-opacity duration-500 animate-pulse"></div>
                            <LogoIcon className="h-9 w-9 text-brand-primary relative z-10 drop-shadow-[0_0_8px_rgba(58,190,254,0.6)]" />
                        </div>
                        <span className="font-orbitron font-bold text-lg md:text-xl tracking-widest text-transparent bg-clip-text bg-gradient-to-r from-brand-primary via-white to-brand-accent group-hover:to-white transition-all">
                            NEWS CLUB
                        </span>
                    </div>

                    {/* CENTRAL NAVIGATION (Desktop) */}
                    <nav className="hidden md:flex items-center gap-1 bg-white/5 rounded-full px-2 py-1.5 border border-white/5 shadow-[inset_0_1px_0_0_rgba(255,255,255,0.05)] backdrop-blur-md">

                        <button 
                            onClick={() => onToggleViewMode('grid')}
                            className={navButtonStyle(viewMode === 'grid', 'brand-primary', 'rgba(58,190,254,0.2)')}
                        >
                            <HomeIcon className="h-4 w-4" />
                            <span>HOME</span>
                        </button>

                        <div className="relative">
                            <button 
                                onClick={toggleSearch}
                                className={navButtonStyle(isSearchExpanded, 'brand-accent', 'rgba(40,255,211,0.2)')}
                            >
                                <CompassIcon className="h-4 w-4" />
                                <span>EXPLORE</span>
                            </button>

                            {isSearchExpanded && (
                                <form 
                                    onSubmit={handleSearch}
                                    className="absolute top-full left-1/2 -translate-x-1/2 mt-4 w-80 bg-[#050505]/90 backdrop-blur-2xl border border-white/10 rounded-xl p-2 shadow-[0_0_30px_rgba(40,255,211,0.15)] flex items-center gap-2 z-50 animate-scale-in"
                                >
                                    <SearchIcon className="h-5 w-5 text-brand-accent ml-2" />
                                    <input
                                        type="text"
                                        value={query}
                                        onChange={(e) => setQuery(e.target.value)}
                                        placeholder="Access Global Intelligence..."
                                        className="bg-transparent border-none focus:ring-0 text-sm text-white w-full placeholder-white/30 font-orbitron"
                                        autoFocus
                                    />
                                    <button type="button" onClick={() => setIsSearchExpanded(false)} className="p-1 hover:text-brand-accent transition-colors">
                                        <CloseIcon className="h-4 w-4" />
                                    </button>
                                </form>
                            )}
                        </div>

                        <button 
                            onClick={onOpenChat}
                            className={navButtonStyle(false, 'brand-primary', '')}
                        >
                            <BoltIcon className="h-4 w-4" />
                            <span>AI CHAT</span>
                        </button>

                        <button 
                            onClick={() => onToggleViewMode('reels')}
                            className={navButtonStyle(viewMode === 'reels', 'brand-secondary', 'rgba(123,47,255,0.2)')}
                        >
                            <ReelsIcon className="h-4 w-4" />
                            <span>REELS</span>
                        </button>

                        {userRole === 'admin' && (
                            <button
                                onClick={() => onToggleViewMode('admin')}
                                className={navButtonStyle(viewMode === 'admin', 'red-500', 'rgba(239,68,68,0.3)')}
                            >
                                <BoltIcon className="h-4 w-4" />
                                <span>ADMIN</span>
                            </button>
                        )}
                    </nav>

                    {/* RIGHT SIDE (Mobile Icons + Profile) */}
                    <div className="flex items-center gap-3">

                        {user && (
                            <button 
                                onClick={() => setShowNotifications(true)}
                                className="p-2 text-brand-text-muted hover:text-white transition-colors hover:bg-white/5 rounded-full relative"
                            >
                                <BellIcon className="h-5 w-5" />
                                {unreadCount > 0 && (
                                    <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-brand-primary rounded-full animate-pulse border border-black"></span>
                                )}
                            </button>
                        )}

                        <button className="p-2 text-brand-text-muted hover:text-brand-accent transition-colors hidden sm:block hover:bg-white/5 rounded-full relative overflow-hidden active:animate-ripple" title="Feedback">
                             <MessageSquareIcon className="h-5 w-5" />
                        </button>

                        <button onClick={toggleSearch} className="md:hidden p-2 text-brand-text-muted hover:text-brand-accent transition-colors hover:bg-white/5 rounded-full relative overflow-hidden active:animate-ripple">
                            <CompassIcon className="h-6 w-6" />
                        </button>

                        {/* 6. PROFILE / LOGIN */}
                        {user ? (
                             <div className="flex items-center gap-3 pl-3 border-l border-white/10">
                                 <button 
                                    onClick={onPersonalizeClick}
                                    className="w-9 h-9 rounded-full overflow-hidden border border-brand-primary/30 hover:border-brand-primary hover:shadow-[0_0_15px_#3ABEFE] transition-all relative active:scale-95 bg-brand-surface"
                                >
                                    {user.photoURL ? (
                                        <img src={user.photoURL} alt="User" className="w-full h-full object-cover" />
                                    ) : (
                                        <UserIcon className="h-5 w-5 m-2 text-brand-text" />
                                    )}
                                </button>
                             </div>
                        ) : (
                             <button 
                                onClick={onPersonalizeClick}
                                className="
                                    group relative flex items-center justify-center gap-2 px-5 py-2 rounded-full overflow-hidden
                                    bg-white/5 border border-brand-primary/50 
                                    text-brand-primary font-orbitron text-[10px] font-bold tracking-wider 
                                    transition-all duration-300 
                                    hover:bg-brand-primary/10 hover:border-brand-primary hover:text-white hover:shadow-[0_0_20px_rgba(58,190,254,0.6)] 
                                    backdrop-blur-sm active:scale-95 active:animate-ripple
                                "
                            >
                                <UserIcon className="h-4 w-4 relative z-10" />
                                <span className="relative z-10">LOGIN</span>
                                 <div className="absolute inset-0 bg-gradient-to-r from-transparent via-brand-primary/20 to-transparent -translate-x-full group-hover:animate-sheen skew-x-12 z-0"></div>
                            </button>
                        )}
                    </div>
                </div>

                {/* Mobile Search Overlay */}
                {isSearchExpanded && (
                    <div className="md:hidden absolute top-16 left-0 right-0 bg-[#050505]/95 backdrop-blur-2xl border-b border-brand-primary/20 p-4 animate-slide-up shadow-2xl z-50">
                        <form onSubmit={handleSearch} className="flex items-center gap-3 bg-white/5 border border-brand-accent/30 rounded-full px-4 py-3 shadow-inner">
                            <SearchIcon className="h-5 w-5 text-brand-accent" />
                            <input
                                type="text"
                                value={query}
                                onChange={(e) => setQuery(e.target.value)}
                                placeholder="Search intelligence..."
                                className="bg-transparent border-none focus:ring-0 text-white w-full placeholder-white/30 text-sm font-orbitron"
                                autoFocus
                            />
                            <button type="button" onClick={() => setIsSearchExpanded(false)}>
                                <CloseIcon className="h-5 w-5 text-brand-text-muted hover:text-white" />
                            </button>
                        </form>
                    </div>
                )}
            </header>

            {/* LOGIN PORTAL MODAL - Kept here if called internally, but Header uses redirect */}
            {showLoginModal && (
                <LoginModal onClose={() => setShowLoginModal(false)} onLoginSuccess={() => setShowLoginModal(false)} />
            )}

            {/* NOTIFICATIONS MODAL */}
            {showNotifications && user && (
                <NotificationsModal userId={user.uid} onClose={() => { setShowNotifications(false); setUnreadCount(0); }} />
            )}
        </>
    );
};

export default Header;

import React, { useState, useEffect } from 'react';
import { UserProfile, AdminMessage } from '../types';
import { getAllUsers, toggleUserStatus, sendAdminMessage } from '../services/dbService';
import { PinIcon, StarIcon, SearchIcon, FilterIcon, MailIcon, WhatsAppIcon, BoltIcon, PaperclipIcon, SendIcon } from './icons';
import { HexagonLoader, HolographicScanner } from './Loaders';

const AdminPanel: React.FC<{ adminUser: UserProfile }> = ({ adminUser }) => {
    const [activeTab, setActiveTab] = useState<'users' | 'messages'>('users');
    const [users, setUsers] = useState<UserProfile[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [filterRole, setFilterRole] = useState<'all' | 'user'>('all');

    // Message State
    const [messageText, setMessageText] = useState('');
    const [selectedRecipients, setSelectedRecipients] = useState<string[]>([]);
    const [channels, setChannels] = useState<{app: boolean, whatsapp: boolean, sms: boolean}>({ app: true, whatsapp: false, sms: false });
    const [targetType, setTargetType] = useState<'specific' | 'all'>('specific');
    const [isSending, setIsSending] = useState(false);

    useEffect(() => {
        loadUsers();
    }, []);

    const loadUsers = async () => {
        setIsLoading(true);
        const data = await getAllUsers();
        setUsers(data);
        setIsLoading(false);
    };

    const handleUserAction = async (uid: string, action: 'pin' | 'star', currentValue: boolean) => {
        const field = action === 'pin' ? 'isPinned' : 'isStarred';
        // Optimistic update
        setUsers(prev => prev.map(u => u.uid === uid ? { ...u, [field]: !currentValue } : u));
        await toggleUserStatus(uid, field, !currentValue);
    };

    const toggleRecipient = (uid: string) => {
        if (targetType !== 'specific') setTargetType('specific');
        setSelectedRecipients(prev => 
            prev.includes(uid) ? prev.filter(id => id !== uid) : [...prev, uid]
        );
    };

    const handleSendMessage = async () => {
        if (!messageText.trim()) return;

        setIsSending(true);
        let finalRecipients = selectedRecipients;

        // Logic for bulk selection
        if (targetType === 'all') {
            finalRecipients = users.map(u => u.uid);
        }

        const msg: AdminMessage = {
            senderId: adminUser.uid,
            senderName: adminUser.displayName,
            recipients: finalRecipients,
            targetType: targetType === 'specific' ? 'user' : targetType,
            content: messageText,
            channels: Object.keys(channels).filter(k => (channels as any)[k]) as any,
            createdAt: new Date(),
            readBy: []
        };

        await sendAdminMessage(msg);

        // Reset
        setIsSending(false);
        setMessageText('');
        alert(`Message sent to ${finalRecipients.length} users via ${msg.channels.join(', ')}`);
    };

    // Filter Logic
    const filteredUsers = users.filter(u => {
        const matchesSearch = u.displayName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                              (u.email && u.email.toLowerCase().includes(searchTerm.toLowerCase()));
        const matchesRole = filterRole === 'all' || u.role === filterRole;
        return matchesSearch && matchesRole;
    }).sort((a, b) => (b.isPinned ? 1 : 0) - (a.isPinned ? 1 : 0)); // Pinned first

    return (
        <div className="h-full bg-black/90 text-white overflow-hidden flex flex-col animate-fade-in relative z-10">
            {/* Header */}
            <header className="p-6 border-b border-brand-secondary/30 flex justify-between items-center bg-[#0a0a0a]">
                <h1 className="text-2xl font-orbitron font-bold text-brand-secondary tracking-widest flex items-center gap-3">
                    <BoltIcon className="text-brand-secondary" /> ADMIN COMMAND
                </h1>
                <div className="flex gap-4">
                    <button 
                        onClick={() => setActiveTab('users')} 
                        className={`px-6 py-2 rounded-full font-bold font-orbitron transition-all ${activeTab === 'users' ? 'bg-brand-secondary text-white shadow-[0_0_15px_#7B2FFF]' : 'text-gray-500 hover:text-white'}`}
                    >
                        USER DATABASE
                    </button>
                    <button 
                        onClick={() => setActiveTab('messages')} 
                        className={`px-6 py-2 rounded-full font-bold font-orbitron transition-all ${activeTab === 'messages' ? 'bg-brand-primary text-white shadow-[0_0_15px_#3ABEFE]' : 'text-gray-500 hover:text-white'}`}
                    >
                        COMMS CENTER
                    </button>
                </div>
            </header>

            <div className="flex-grow p-6 overflow-hidden flex flex-col">

                {/* TAB: USERS */}
                {activeTab === 'users' && (
                    <div className="h-full flex flex-col space-y-4">
                        {/* Filters */}
                        <div className="flex gap-4 mb-4">
                            <div className="relative flex-grow max-w-md">
                                <SearchIcon className="absolute left-3 top-3 h-5 w-5 text-gray-500" />
                                <input 
                                    type="text" 
                                    placeholder="Search agents..." 
                                    value={searchTerm}
                                    onChange={e => setSearchTerm(e.target.value)}
                                    className="w-full bg-white/5 border border-white/10 rounded-full py-2.5 pl-10 pr-4 focus:border-brand-secondary outline-none text-sm"
                                />
                            </div>
                            <div className="flex items-center gap-2 bg-white/5 rounded-full px-4 border border-white/10">
                                <FilterIcon className="h-4 w-4 text-gray-400" />
                                <select 
                                    value={filterRole} 
                                    onChange={(e: any) => setFilterRole(e.target.value)}
                                    className="bg-transparent border-none outline-none text-sm text-gray-300"
                                >
                                    <option value="all">All Roles</option>
                                    <option value="user">Users</option>
