import { decode, decodeAudioData, audioBufferToWav } from '../utils/audioUtils';
import { NewsArticle } from '../types';
import { CloseIcon, SparklesIcon, UploadIcon, PlayIcon, PauseIcon, StopIcon, SoundWaveIcon, DownloadIcon } from './icons';
import AudioVisualizer from './AudioVisualizer';
import { HexagonLoader } from './Loaders';
import { User } from 'firebase/auth';

interface AudioGenerationModalProps {
    articles: NewsArticle[];
    onClose: () => void;
    user: User | null;
    onLoginRequest: () => void;
}

type Mode = 'text' | 'article' | 'ai-conversation';
type Language = 'English' | 'Hindi' | 'Hinglish';
const progressMessages = ["INITIALIZING NEURAL NET", "ANALYZING SYNTAX", "SCRIPTING BROADCAST", "SYNTHESIZING AUDIO WAVES", "FINALIZING OUTPUT"];

const AudioGenerationModal: React.FC<AudioGenerationModalProps> = ({ articles, onClose, user, onLoginRequest }) => {
    // --- UI State ---
    const [mode, setMode] = useState<Mode>('text');
    const [textInput, setTextInput] = useState('');
    const [aiTopicInput, setAiTopicInput] = useState('');
    const [selectedArticleId, setSelectedArticleId] = useState<number | null>(articles[0]?.id || null);
    const [language, setLanguage] = useState<Language>('English');

    const [status, setStatus] = useState<'idle' | 'generating' | 'ready' | 'playing' | 'paused' | 'error'>('idle');
    const [progressMessage, setProgressMessage] = useState('');
    const [error, setError] = useState('');

    // --- Audio State ---
    const [volume, setVolume] = useState(1);
    const [playbackRate, setPlaybackRate] = useState(1);

    // VISUALIZER STATE
    const [analyserForVisualizer, setAnalyserForVisualizer] = useState<AnalyserNode | null>(null);

    // --- Audio Refs ---
    const audioContextRef = useRef<AudioContext | null>(null);
    const gainNodeRef = useRef<GainNode | null>(null);
    const analyserNodeRef = useRef<AnalyserNode | null>(null);
    const audioBufferRef = useRef<AudioBuffer | null>(null);
    const sourceRef = useRef<AudioBufferSourceNode | null>(null);

    const fileInputRef = useRef<HTMLInputElement>(null);

    // --- Cleanup on Unmount ---
    useEffect(() => {
        return () => {
            stopAudio();
            if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
                audioContextRef.current.close();
            }
            // Stop TTS Demo
            window.speechSynthesis.cancel();
        };
    }, []);

    const initAudioContext = useCallback(() => {
        if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
             const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
             const ctx = new AudioContext(); 

             const gain = ctx.createGain();
             const analyser = ctx.createAnalyser();

             // Connection: Gain -> Analyser -> Destination
             gain.connect(analyser);
             analyser.connect(ctx.destination);

             audioContextRef.current = ctx;
             gainNodeRef.current = gain;
             analyserNodeRef.current = analyser;

             setAnalyserForVisualizer(analyser);
        }
        return audioContextRef.current;
    }, []);

    const stopAudio = useCallback(() => {
        if (sourceRef.current) {
            try { sourceRef.current.stop(); } catch(e) {}
            sourceRef.current.disconnect();
            sourceRef.current = null;
        }
        if (status === 'playing' || status === 'paused') {
            setStatus('ready');
        }
    }, [status]);

    const pauseAudio = useCallback(() => {
        if (audioContextRef.current?.state === 'running') {
            audioContextRef.current.suspend();
            setStatus('paused');
        }
    }, []);

    const resumeAudio = useCallback(async () => {
        if (audioContextRef.current?.state === 'suspended') {
            await audioContextRef.current.resume();
            setStatus('playing');
        }
    }, []);

    const playAudioBuffer = useCallback((offset: number = 0) => {
        const ctx = audioContextRef.current;
        const gain = gainNodeRef.current;
        const buffer = audioBufferRef.current;

        if (!buffer || !ctx || !gain) return;

        if (ctx.state === 'suspended') {
            ctx.resume();
        }

        if (sourceRef.current) {
            try { sourceRef.current.stop(); } catch(e){}
            sourceRef.current.disconnect();
        }

        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(gain);

        gain.gain.value = volume;
        source.playbackRate.value = playbackRate;

        source.onended = () => {
            if (ctx.state === 'running') {
               setStatus('ready');
               sourceRef.current = null;
            }
        };

        source.start(0, offset);
        sourceRef.current = source;
        setStatus('playing');
   }, [volume, playbackRate]);

    const handlePlayPauseClick = async () => {
        const ctx = initAudioContext();

        if (status === 'playing') {
            pauseAudio();
        } else if (status === 'paused') {
            await resumeAudio();
        } else if (status === 'ready') {
            if (ctx.state === 'suspended') await ctx.resume();
            playAudioBuffer(0);
        }
    };

    const handleDownload = () => {
        if (!audioBufferRef.current) return;

        try {
            const blob = audioBufferToWav(audioBufferRef.current);
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.style.display = 'none';
            a.href = url;
            // Naming it .wav to ensure compatibility, user asked for mp3 but wav is the native browser format for lossless.
            // Modern players handle wav fine.
            a.download = `news_audio_${Date.now()}.wav`; 
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
            document.body.removeChild(a);
        } catch (err) {
            console.error("Download failed", err);
            setError("Failed to process audio for download.");
        }
    };

    useEffect(() => {
        if (gainNodeRef.current) gainNodeRef.current.gain.value = volume;
    }, [volume]);

    useEffect(() => {
        if (sourceRef.current) sourceRef.current.playbackRate.value = playbackRate;
    }, [playbackRate]);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file && file.type === 'text/plain') {
            const reader = new FileReader();
            reader.onload = (event) => {
                if (event.target?.result) {
                    setTextInput(event.target.result as string);
                }
            };
            reader.readAsText(file);
        }
    };

    const handleGenerate = async () => {
        // AUTH CHECK REMOVED to allow guest access

        if (status === 'generating') return;

        if (mode === 'text' && !textInput.trim()) { setError("Please enter text or upload a file."); return; }
        if (mode === 'ai-conversation' && !aiTopicInput.trim()) { setError("Please enter a topic."); return; }

        setError('');
        setStatus('generating');
        setProgressMessage(progressMessages[0]);

        try {
            const ctx = initAudioContext();
            if (ctx.state === 'suspended') await ctx.resume();

            let audioData: string | null = null;
            let textToProcess = '';

            if (mode === 'article') {
                const article = articles.find(a => a.id === selectedArticleId);
                if (!article) throw new Error("Article not found");
                textToProcess = article.content;
                setProgressMessage(progressMessages[2]);
                audioData = await generateNewsBroadcastSpeech(textToProcess, language);
            } 
            else if (mode === 'text') {
                textToProcess = textInput;
                setProgressMessage(progressMessages[3]);
                audioData = await generateSpeechFromText(textToProcess);
            }
            else if (mode === 'ai-conversation') {
                textToProcess = `Breaking news report about: ${aiTopicInput}`;
                setProgressMessage("GENERATING CONTENT...");
                audioData = await generateNewsBroadcastSpeech(textToProcess, language);
            }

            if (!audioData) throw new Error("Failed to generate audio stream.");

            setProgressMessage(progressMessages[4]);

            const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
            audioBufferRef.current = buffer;

            setStatus('ready');
            playAudioBuffer(0);

        } catch (err: any) {
            console.error(err);
            setError(err.message || "Generation failed.");
            setStatus('error');
        }
    };

    return (
        <div className="fixed inset-0 bg-[#050505]/95 backdrop-blur-md flex items-center justify-center z-[60] p-4 animate-fade-in" onClick={onClose}>
            <div 
                className="bg-[#050505]/80 backdrop-blur-2xl w-full max-w-4xl max-h-[90vh] rounded-[24px] shadow-[0_0_50px_rgba(123,47,255,0.15)] border border-white/10 ring-1 ring-white/5 flex flex-col relative overflow-hidden" 
                onClick={e => e.stopPropagation()}
            >
                {/* Decor */}
                <div className="absolute inset-0 bg-grid-pattern opacity-[0.05] pointer-events-none"></div>
                <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-brand-secondary to-transparent z-50 animate-scan-line"></div>

                <header className="p-5 border-b border-brand-secondary/20 flex justify-between items-center bg-white/5 backdrop-blur-xl relative z-10">
                     <div className="flex items-center gap-3">
                        <div className="p-2 bg-brand-secondary/10 rounded-full border border-brand-secondary/30 text-brand-secondary shadow-[0_0_10px_rgba(123,47,255,0.2)]">
                            <SoundWaveIcon className="w-5 h-5" />
                        </div>
                        <h2 className="font-orbitron text-xl text-white tracking-wider">
                            AUDIO <span className="text-brand-secondary">SYNTHESIS</span>
                        </h2>
                    </div>
                    <button onClick={onClose} className="text-brand-text-muted hover:text-white transition-colors p-2 hover:bg-white/10 rounded-full border border-transparent hover:border-white/10 active:scale-95">
                        <CloseIcon />
                    </button>
                </header>

                <div className="flex-grow p-6 md:p-8 overflow-y-auto relative z-10">

                    {/* Mode Selection */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
                         {[
                            { id: 'article', label: 'Article Read', icon: <SoundWaveIcon className="w-4 h-4" /> },
                            { id: 'text', label: 'Custom Text', icon: <UploadIcon className="w-4 h-4" /> },
                            { id: 'ai-conversation', label: 'Topic Generation', icon: <SparklesIcon className="w-4 h-4" /> }
                         ].map(option => (
                             <button
                                key={option.id}
                                onClick={() => setMode(option.id as Mode)}
                                className={`
                                    flex items-center justify-center gap-2 py-3 rounded-xl border transition-all duration-300 font-bold font-orbitron text-xs tracking-wider
                                    ${mode === option.id 
                                        ? 'bg-brand-secondary text-white border-brand-secondary shadow-[0_0_15px_rgba(123,47,255,0.4)]' 
                                        : 'bg-white/5 border-white/10 text-brand-text-muted hover:bg-white/10 hover:text-white'}
                                `}
                             >
                                 {option.icon} {option.label}
                             </button>
                         ))}
                    </div>

                    {/* Dynamic Content Based on Mode */}
                    <div className="bg-white/5 border border-white/10 rounded-[22px] p-6 mb-6">
                        {mode === 'article' && (
                            <div className="space-y-4">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Select Article</label>
                                <div className="grid grid-cols-1 gap-3 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                                    {articles.map(article => (
                                        <button
                                            key={article.id}
                                            onClick={() => setSelectedArticleId(article.id)}
                                            className={`
                                                w-full text-left p-4 rounded-xl border transition-all
                                                ${selectedArticleId === article.id 
                                                    ? 'bg-brand-secondary/20 border-brand-secondary/50 text-white shadow-inner' 
                                                    : 'bg-black/20 border-white/5 text-gray-400 hover:bg-black/40 hover:text-gray-200'}
                                            `}
                                        >
                                            <div className="font-bold text-sm mb-1 truncate">{article.title}</div>
                                            <div className="text-[10px] opacity-70 truncate">{article.summary}</div>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        {mode === 'text' && (
                            <div className="space-y-4">
                                <div className="flex justify-between items-center">
                                    <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Input Text</label>
                                    <button 
                                        onClick={() => fileInputRef.current?.click()}
                                        className="text-[10px] text-brand-secondary flex items-center gap-1 hover:underline"
                                    >
                                        <UploadIcon className="w-3 h-3" /> Upload .txt
                                    </button>
                                    <input 
                                        type="file" 
                                        ref={fileInputRef} 
                                        className="hidden" 
                                        accept=".txt" 
                                        onChange={handleFileChange} 
                                    />
                                </div>
                                <textarea
                                    value={textInput}
                                    onChange={(e) => setTextInput(e.target.value)}
                                    placeholder="Type or paste text here for neural speech synthesis..."
                                    className="w-full h-40 bg-black/40 border border-white/10 rounded-xl p-4 text-sm text-white focus:border-brand-secondary outline-none transition-colors resize-none placeholder-gray-600 font-light"
                                />
                            </div>
                        )}

                        {mode === 'ai-conversation' && (
                            <div className="space-y-4">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Topic / Context</label>
                                <input
                                    type="text"
                                    value={aiTopicInput}
                                    onChange={(e) => setAiTopicInput(e.target.value)}
                                    placeholder="e.g., The future of space travel..."
                                    className="w-full bg-black/40 border border-white/10 rounded-xl p-4 text-sm text-white focus:border-brand-secondary outline-none transition-colors placeholder-gray-600 font-light"
                                />
                                <p className="text-[10px] text-brand-text-muted">
                                    The AI will generate a dynamic script and two-person news broadcast simulation based on this topic.
                                </p>
                            </div>
                        )}

                        {/* Language Selection */}
                         <div className="mt-6 pt-6 border-t border-white/10">
                            <label className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-3 block">Voice Model Language</label>
                            <div className="flex gap-4">
                                {(['English', 'Hindi', 'Hinglish'] as Language[]).map(l => (
                                    <label key={l} className="flex items-center gap-2 cursor-pointer group">
                                        <div className={`w-4 h-4 rounded-full border flex items-center justify-center ${language === l ? 'border-brand-secondary' : 'border-gray-600'}`}>
                                            {language === l && <div className="w-2 h-2 rounded-full bg-brand-secondary"></div>}
                                        </div>
                                        <span className={`text-sm ${language === l ? 'text-white' : 'text-gray-500 group-hover:text-gray-300'}`}>{l}</span>
                                        <input type="radio" className="hidden" checked={language === l} onChange={() => setLanguage(l)} />
                                    </label>
                                ))}
                            </div>
                        </div>
                    </div>

                    {error && (
                        <div className="mb-6 p-4 bg-red-900/20 border border-red-500/50 rounded-xl text-red-200 text-xs text-center font-mono">
                            ERROR: {error}
                        </div>
                    )}

                    {/* Action Button */}
                    <div className="flex justify-center">
                        {status === 'generating' ? (
                            <HexagonLoader size="md" text={progressMessage} />
                        ) : (
                            <button
                                onClick={handleGenerate}
                                className="
                                    group relative px-10 py-4 rounded-full overflow-hidden
                                    bg-gradient-to-r from-brand-secondary to-purple-600
                                    text-white font-orbitron font-bold tracking-widest shadow-[0_0_30px_rgba(123,47,255,0.4)]
                                    hover:shadow-[0_0_50px_rgba(123,47,255,0.6)] hover:scale-105
                                    active:scale-95 transition-all
                                "
                            >
                                <span className="relative z-10 flex items-center gap-3">
                                    INITIATE SYNTHESIS <SoundWaveIcon className="w-5 h-5" />
                                </span>
                                <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-500 skew-x-12 z-0"></div>
                            </button>
                        )}
                    </div>
                </div>

                {/* Audio Player Footer */}
                {(status === 'ready' || status === 'playing' || status === 'paused') && (
                    <footer className="p-4 border-t border-white/10 bg-white/5 backdrop-blur-xl relative z-20 animate-slide-up">
                         <div className="flex items-center gap-4">
                             {/* Play Controls */}
                             <button 
                                onClick={handlePlayPauseClick}
                                className="w-12 h-12 rounded-full bg-white text-black flex items-center justify-center hover:scale-110 transition-transform shadow-[0_0_20px_rgba(255,255,255,0.3)]"
                             >
                                 {status === 'playing' ? <PauseIcon className="w-6 h-6" /> : <PlayIcon className="w-6 h-6 ml-1" />}
                             </button>
                             <button 
                                onClick={stopAudio}
                                className="p-3 rounded-full bg-white/10 text-white hover:bg-white/20 transition-colors"
                             >
                                 <StopIcon className="w-5 h-5" />
                             </button>

                             {/* Visualizer */}
                             <div className="flex-grow h-12 bg-black/40 rounded-lg overflow-hidden relative border border-white/5">
                                 <AudioVisualizer analyserNode={analyserForVisualizer} width={400} height={48} barColor="#7B2FFF" gap={2} />
                             </div>

                             {/* Download Button */}
                             <button 
                                onClick={handleDownload}
                                className="hidden md:flex items-center gap-2 px-4 py-2 rounded-full bg-brand-primary/10 border border-brand-primary/30 text-brand-primary hover:bg-brand-primary hover:text-black transition-all text-xs font-bold font-orbitron"
                                title="Download Audio"
                             >
                                <DownloadIcon className="w-4 h-4" /> <span>SAVE</span>
                             </button>

                             {/* Settings */}
                             <div className="hidden md:flex flex-col gap-1 w-24">
                                <div className="flex justify-between text-[10px] text-gray-400 font-mono">
                                    <span>VOL</span>
                                    <span>{Math.round(volume * 100)}%</span>
                                </div>
                                <input 
                                    type="range" 
                                    min="0" max="1" step="0.01" 
                                    value={volume} 
                                    onChange={(e) => setVolume(Number(e.target.value))}
                                    className="w-full h-1 bg-gray-700 rounded-full appearance-none cursor-pointer accent-brand-secondary"
                                />
                             </div>
                         </div>
                    </footer>
                )}
            </div>
        </div>
    );
};

export default AudioGenerationModal;

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { HolographicScanner } from './Loaders';

interface ErrorBoundaryProps {
  children?: ReactNode;
  componentName?: string;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error(`Uncaught error in ${this.props.componentName || 'Unknown Component'}:`, error, errorInfo);
  }

  handleReset = () => {
    this.setState({ hasError: false, error: null });
  };

  render() {
    if (this.state.hasError) {
      return (
        <div className="w-full h-full min-h-[200px] flex flex-col items-center justify-center p-6 bg-brand-surface/50 border border-brand-accent/30 rounded-lg backdrop-blur-sm animate-fade-in">
          <div className="text-brand-accent font-orbitron text-xl mb-4 animate-pulse">
            SYSTEM FAILURE DETECTED
          </div>
          <div className="text-brand-text-muted text-center mb-6 max-w-md">
            Component <span className="text-white font-bold">{this.props.componentName || 'Unknown'}</span> encountered a critical error.
            <br />
            <span className="text-xs font-mono mt-2 block opacity-70">
              {this.state.error?.message}
            </span>
          </div>
          <HolographicScanner text="ATTEMPTING RECOVERY" />
          <button
            onClick={this.handleReset}
            className="mt-6 px-6 py-2 bg-brand-accent/20 border border-brand-accent text-brand-accent rounded hover:bg-brand-accent/40 transition-colors font-orbitron tracking-widest text-xs"
          >
            REBOOT COMPONENT
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

