                                <div className="space-y-2">
                                    <label className="text-[10px] uppercase font-bold text-brand-primary tracking-widest ml-1">Mission Statement / Bio</label>
                                    <textarea 
                                        value={formData.bio}
                                        onChange={e => setFormData({...formData, bio: e.target.value})}
