import React, { Component, ErrorInfo, ReactNode } from 'react';
import { HolographicScanner } from './Loaders';

interface ErrorBoundaryProps {
  children?: ReactNode;
  componentName?: string;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  public static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error(`Uncaught error in ${this.props.componentName || 'Unknown Component'}:`, error, errorInfo);
  }

  public handleReset = () => {
    this.setState({ hasError: false, error: null });
  };

  public render() {
    if (this.state.hasError) {
      return (
        <div className="w-full h-full min-h-[200px] flex flex-col items-center justify-center p-6 bg-brand-surface/50 border border-brand-accent/30 rounded-lg backdrop-blur-sm animate-fade-in">
          <div className="text-brand-accent font-orbitron text-xl mb-4 animate-pulse">
            SYSTEM FAILURE DETECTED
          </div>
          <div className="text-brand-text-muted text-center mb-6 max-w-md">
            Component <span className="text-white font-bold">{this.props.componentName || 'Unknown'}</span> encountered a critical error.
            <br />
            <span className="text-xs font-mono mt-2 block opacity-70">
              {this.state.error?.message}
            </span>
          </div>
          <HolographicScanner text="ATTEMPTING RECOVERY" />
          <button
            onClick={this.handleReset}
            className="mt-6 px-6 py-2 bg-brand-accent/20 border border-brand-accent text-brand-accent rounded hover:bg-brand-accent/40 transition-colors font-orbitron tracking-widest text-xs"
          >
            REBOOT COMPONENT
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

import { GoogleGenAI, Chat, GenerateContentResponse, Modality, Part } from "@google/genai";
import type { SearchResult, NewsArticle, AIFeedback } from '../types';

function getAiClient() {
    let apiKey: string | undefined;

    // 1. Check for Vite environment variable (Vercel support)
    if (typeof import.meta !== 'undefined' && (import.meta as any).env && (import.meta as any).env.VITE_API_KEY) {
        apiKey = (import.meta as any).env.VITE_API_KEY;
    }

    // 2. Check for Next.js / Vercel Public variable
    if (!apiKey && typeof process !== 'undefined' && process.env) {
        apiKey = process.env.NEXT_PUBLIC_API_KEY;
    }

    // 3. Safe extraction of the key from process.env (Local/Node fallback)
    if (!apiKey) {
        try {
            apiKey = process.env.API_KEY;
        } catch (e) {
            // process is not defined in the browser environment
        }
    }

    // 4. Validation
    if (!apiKey) {
        throw new Error("API Key is missing. Please set VITE_API_KEY in your environment.");
    }

    return new GoogleGenAI({ apiKey });
}

let chatInstance: Chat | null = null;

function getChatInstance(forceReset: boolean = false): Chat {
    if (forceReset || !chatInstance) {
        const ai = getAiClient();
        chatInstance = ai.chats.create({
            model: 'gemini-2.5-flash',
            config: {
                // STRICT TOPIC RESTRICTION ADDED
                systemInstruction: 'You are a dedicated News & Technology Reporter for the News Club App. You ONLY discuss news, current events, science, technology, and futuristic concepts. If a user asks about personal advice, creative writing (unrelated to news), or general chit-chat, politely refuse and steer the conversation back to the latest news or technological updates. Keep responses concise, professional, and informative.',
            },
        });
    }
    return chatInstance;
}

// Function to force a new chat session (useful when UI resets)
export function resetChat() {
    getChatInstance(true);
}

