        throw error;
    }
}

export async function generateFuturisticArticles(count: number = 4): Promise<Omit<NewsArticle, 'id' | 'isSummaryLoading'>[]> {
    try {
        const ai = getAiClient();
        const prompt = `Generate ${count} distinct, creative, and futuristic sci-fi news articles.
        Topics can include AI, Space Colonization, Cybernetics, Biotechnology, Quantum Computing, or Nanotech.

        Return the result as a strict JSON array of objects with the following keys:
        - title: string
        - summary: string (2 sentences)
        - content: string (3-4 paragraphs)
        - category: string (One word e.g. 'Cybernetics', 'Space')
        - source: string (Fictional news source name)

        IMPORTANT: Return ONLY the raw JSON. Do not wrap it in markdown code blocks like \`\`\`json ... \`\`\`. Do not add any conversational text.`;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                responseMimeType: 'application/json',
            }
        });

        let rawText = response.text || "[]";

        // CLEANUP: Remove markdown code blocks if they exist (common model behavior even with JSON mode)
        rawText = rawText.replace(/```json/g, '').replace(/```/g, '').trim();

        const articles = JSON.parse(rawText);

        return articles.map((article: any, index: number) => ({
            ...article,
            image: `https://picsum.photos/seed/${Date.now() + index + Math.random()}/600/400`,
        }));

    } catch (error) {
        console.error("Failed to generate AI articles:", error);
        return [];
    }
}

// --- NEW FUNCTION: Analyze Student Video Submission ---
export async function analyzeStudentVideo(videoFile: File): Promise<AIFeedback> {
    const ai = getAiClient();

    // Convert File to Base64
    const base64Data = await new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(videoFile);
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
        reader.onerror = error => reject(error);
    });

    const prompt = `
        You are an expert news reporting coach. Analyze this student's news reporting video submission.
        Evaluation Criteria:
        1. Pronunciation & Diction
        2. Speaking Speed (Pacing)
        3. Confidence & Body Language
        4. Clarity of Message
        5. Logical Flow
        6. Background Noise Level

        Return a strict JSON object with this structure:
        {
            "pronunciationScore": number (0-100),
            "speedScore": number (0-100, where 50 is ideal, <30 is too slow, >70 is too fast),
            "confidenceScore": number (0-100),
            "clarityScore": number (0-100),
            "tips": ["tip1", "tip2", "tip3"],
            "mistakes": ["mistake1", "mistake2"],
            "strengths": ["strength1", "strength2"]
        }
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: [
                {
                    parts: [
                        { text: prompt },
                        { 
                            inlineData: { 
                                mimeType: videoFile.type, 
                                data: base64Data 
                            } 
                        }
                    ]
                }
            ],
            config: {
                responseMimeType: 'application/json'
            }
        });

        if (!response.text) throw new Error("No analysis generated.");
        return JSON.parse(response.text) as AIFeedback;

    } catch (error) {
        console.error("Video analysis failed:", error);
        throw new Error("Failed to analyze video. Ensure the file is valid and under size limits.");
    }
}

import React, { useEffect, useState } from 'react';
import { AdminMessage } from '../types';
import { getUserMessages, markMessageRead } from '../services/dbService';
import { CloseIcon, BellIcon, BoltIcon } from './icons';
import { HolographicScanner } from './Loaders';

interface NotificationsModalProps {
    userId: string;
    onClose: () => void;
}

const NotificationsModal: React.FC<NotificationsModalProps> = ({ userId, onClose }) => {
    const [messages, setMessages] = useState<AdminMessage[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetch = async () => {
            try {
                let msgs = await getUserMessages(userId);

                // Fallback System Message if empty
                if (msgs.length === 0) {
                    const welcomeMsg: AdminMessage = {
                        id: 'system-welcome',
                        senderId: 'system',
                        senderName: 'News Club System',
                        recipients: [userId],
                        targetType: 'user',
                        content: "Welcome to News Club. This is your secure feed for admin updates and personalized alerts. Stay tuned for intelligence briefings.",
                        channels: ['app'],
                        readBy: [],
                        createdAt: { seconds: Date.now() / 1000 }
                    };
                    msgs = [welcomeMsg];
                }

                setMessages(msgs);

                // Mark unread as read (except system dummy)
                msgs.forEach(msg => {
                    if (msg.id !== 'system-welcome' && !msg.readBy?.includes(userId) && msg.id) {
                        markMessageRead(msg.id, userId);
                    }
                });
            } catch (error) {
                console.error("Failed to load notifications", error);
            } finally {
                setLoading(false);
            }
        };
        fetch();
    }, [userId]);

    return (
        <div className="fixed inset-0 bg-[#050505]/95 backdrop-blur-md flex items-center justify-center z-[70] p-4 animate-fade-in" onClick={onClose}>
            <div 
                className="bg-[#0a0a0a]/90 w-full max-w-md h-[70vh] rounded-[24px] border border-white/10 shadow-[0_0_50px_rgba(255,255,255,0.1)] flex flex-col relative overflow-hidden"
                onClick={e => e.stopPropagation()}
            >
                <header className="p-5 border-b border-white/10 flex justify-between items-center bg-white/5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-brand-primary/10 rounded-full text-brand-primary">
                            <BellIcon className="h-5 w-5" />
                        </div>
                        <h2 className="font-orbitron text-lg text-white">NOTIFICATIONS</h2>
                    </div>
                    <button onClick={onClose}><CloseIcon className="text-gray-400 hover:text-white" /></button>
                </header>

                <div className="flex-grow overflow-y-auto p-4 space-y-4">
                    {loading ? <div className="pt-10"><HolographicScanner text="DECRYPTING" /></div> : 
                     messages.length === 0 ? (
                        <div className="text-center text-gray-500 mt-20 text-sm">No new transmissions.</div>
                     ) : (
                        messages.map((msg, idx) => (
                            <div key={idx} className="bg-white/5 border border-white/10 rounded-xl p-4 animate-slide-up relative overflow-hidden group hover:border-brand-primary/30 transition-all">
                                <div className="absolute top-0 left-0 w-1 h-full bg-brand-primary"></div>
                                <div className="flex justify-between items-start mb-2">
                                    <span className="text-brand-primary text-xs font-bold font-orbitron flex items-center gap-1">
                                        <BoltIcon className="w-3 h-3" /> {msg.senderName || 'ADMIN'}
                                    </span>
                                    <span className="text-[10px] text-gray-500">
                                        {msg.createdAt?.seconds ? new Date(msg.createdAt.seconds * 1000).toLocaleDateString() : 'Just now'}
                                    </span>
                                </div>
                                <p className="text-sm text-gray-200 leading-relaxed font-light">{msg.content}</p>
                            </div>
                        ))
                     )}
                </div>
            </div>
        </div>
    );
};

